INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('898fbd65-4f24-5c58-ab53-6725a8806907', '8f1863b5-6dbb-5779-8622-2267992146f3', 'دخل المعلّم القسم وبدأ يشرح. ما التصرّف المؤدّب؟', '[{"id":"a","text":"أُكمل اللعب مع جاري"},{"id":"b","text":"أصرخ لأُسلّم عليه"},{"id":"c","text":"أجلس بهدوءٍ وأُصغي إليه"},{"id":"d","text":"أخرج من القسم"}]'::jsonb, 'c', 'حين يشرح المعلّم أجلس بهدوءٍ وأُصغي إليه، وهذا أدبٌ حسن في القسم.', 1)
