INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3fd2d707-8433-51d9-8556-75030dae094c', '8f1863b5-6dbb-5779-8622-2267992146f3', 'أردتَ أن تسأل المعلّم سؤالًا. ما الترتيب الصحيح؟', '[{"id":"a","text":"أصرخ بالسؤال ثمّ أرفع إصبعي"},{"id":"b","text":"أُقاطع المعلّم ثمّ أسأل"},{"id":"c","text":"أقف وأتكلّم دون إذن"},{"id":"d","text":"أرفع إصبعي، أنتظر الإذن، ثمّ أسأل"}]'::jsonb, 'd', 'الترتيب الصحيح: أرفع إصبعي، ثمّ أنتظر إذن المعلّم، ثمّ أسأل بهدوء.', 2)
