INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c72f0cda-bf39-5ecf-99f8-6353505072ee', '8f1863b5-6dbb-5779-8622-2267992146f3', 'زميلك يتكلّم وأنت تريد أن تقول رأيك بسرعة. ما الصواب؟', '[{"id":"a","text":"أُقاطعه فورًا"},{"id":"b","text":"أنتظر حتّى ينتهي ثمّ أستأذن"},{"id":"c","text":"أرفع صوتي فوق صوته"},{"id":"d","text":"أدفعه ليسكت"}]'::jsonb, 'b', 'أنتظر حتّى ينتهي زميلي ثمّ أستأذن. الخطأ الشائع المقاطعة لظنّ أنّ رأيي أهمّ، والصواب احترام دور الآخرين.', 3)
