INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('417a86b1-5c24-5499-b9ca-6855280e957d', '5ea538ce-59f8-5e48-a3b7-dfe377eefc92', 'أرادت أمّي أن أُساعدها، وأنا ألعب. ما الصواب؟', '[{"id":"a","text":"أُكمل اللّعب وأتركها"},{"id":"b","text":"أرفع صوتي عليها"},{"id":"c","text":"أترك اللّعب وأُساعدها"},{"id":"d","text":"أتظاهر بأنّي لم أسمع"}]'::jsonb, 'c', 'أترك اللّعب وأُسارع إلى مساعدة أمّي؛ فطاعة الوالدين في المعروف ومساعدتهما من البرّ. الخطأ الشائع أن نُؤثِر اللّعب على مساعدتهما.', 3)
