INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2cf5719-7a7d-53c2-a3c3-ee82a3d3ddad', '5ea538ce-59f8-5e48-a3b7-dfe377eefc92', 'قال رسول الله ﷺ: «المسلمُ مَن سَلِمَ المسلمونَ مِن لِسانِه و...».', '[{"id":"a","text":"مالِه"},{"id":"b","text":"يَدِه"},{"id":"c","text":"بيتِه"},{"id":"d","text":"ثوبِه"}]'::jsonb, 'b', 'الحديث: المسلم من سلم المسلمون من لسانه ويده، أي لا يؤذي الناس بالكلام ولا باليد. الخطأ الشائع نسيان «اليد» بعد «اللسان».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c16cb81a-293d-5556-aaed-deb8c66789fc', '5ea538ce-59f8-5e48-a3b7-dfe377eefc92', 'معنى «سلم المسلمون من لسانه» أنّ المسلم:', '[{"id":"a","text":"يضرب الناس"},{"id":"b","text":"يأخذ أموالهم"},{"id":"c","text":"يكسر الأشياء"},{"id":"d","text":"لا يشتم ولا يؤذي بالكلام"}]'::jsonb, 'd', '«سلم من لسانه» يعني أنّه لا يشتم ولا يسبّ ولا يؤذي أحدًا بالكلام. الخطأ الشائع ظنّ اللسان آلةً للأذى، والمسلم يحفظه.', 5)
