INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('101c7852-8937-51ea-9604-a5201be1ed90', 'd46d18b4-594c-5bff-8f02-1fd43421471a', 'النبيّ ﷺ يصف المسلم الحقّ بأنّه:', '[{"id":"a","text":"أقوى الناس في الضرب"},{"id":"b","text":"أكثر الناس كلامًا"},{"id":"c","text":"من سلم المسلمون من لسانه ويده"},{"id":"d","text":"أسرع الناس جريًا"}]'::jsonb, 'c', 'قال النبيّ ﷺ: المسلم من سلم المسلمون من لسانه ويده، فالمسلم الحقّ لا يؤذي بكلامٍ ولا بيد. الخطأ الشائع ربط القوّة بالأذى، والمسلم يكفّ أذاه.', 4)
