INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1421ae50-83ea-56c1-9ce8-208c4b8391eb', 'd46d18b4-594c-5bff-8f02-1fd43421471a', 'صديقٌ يضرب زملاءه ويشتمهم ويقول: أنا مسلمٌ قويّ. ما الصواب؟', '[{"id":"a","text":"هذا ليس من صفات المسلم؛ المسلم يسلم الناس من لسانه ويده"},{"id":"b","text":"هو محقّ، القوّة في الضرب"},{"id":"c","text":"الشتم يدلّ على الشجاعة"},{"id":"d","text":"إيذاء الناس أمرٌ جيّد"}]'::jsonb, 'a', 'الضرب والشتم ليسا من صفات المسلم؛ فالمسلم من سلم الناس من لسانه ويده. الخطأ الشائع ظنّ الأذى قوّةً، والمسلم طيّبٌ كافٌّ لأذاه.', 5)
