INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4122c37d-c615-58df-9bc6-b7f1cd0f962d', 'd46d18b4-594c-5bff-8f02-1fd43421471a', 'لماذا يُحبّ الله والناسُ المسلمَ الطيّب؟', '[{"id":"a","text":"لأنّه يؤذي الناس"},{"id":"b","text":"لأنّه يرفع صوته"},{"id":"c","text":"لأنّه يُغضب والديه"},{"id":"d","text":"لأنّه يبرّ والديه ويحفظ لسانه ويده"}]'::jsonb, 'd', 'المسلم الطيّب يبرّ والديه ويحفظ لسانه ويده فلا يؤذي أحدًا، فيُحبّه الله ويُحبّه الناس. الخطأ الشائع ظنّ المحبّة تُنال بالأذى، وهي تُنال بالخير.', 6)
