INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6749344f-ece9-5860-a225-8e9d10f9d53d', '6087495c-7a7e-541e-a66e-a18b184cb8ee', 'في سورة الكوثر أمر الله نبيّه ﷺ أن يصلّي لربّه. لماذا؟', '[{"id":"a","text":"لأنّه خائف"},{"id":"b","text":"لأنّه جائع"},{"id":"c","text":"لأنّه نعس"},{"id":"d","text":"شكرًا لله على الخير الكثير الذي أعطاه"}]'::jsonb, 'd', 'قال الله: فصلّ لربّك وانحر، أي صلِّ لله شكرًا له على «الكوثر» وهو الخير الكثير الذي أعطاه نبيّه ﷺ.', 2)
