INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a173664d-c34a-5de3-a93a-6b186fa575f2', '6087495c-7a7e-541e-a66e-a18b184cb8ee', 'في سورة النصر «يدخلون في دين الله أفواجًا». «أفواجًا» معناها:', '[{"id":"a","text":"ببطءٍ شديد"},{"id":"b","text":"جماعاتٍ كثيرة"},{"id":"c","text":"شخصًا واحدًا"},{"id":"d","text":"في المساء"}]'::jsonb, 'b', '«أفواجًا» تعني جماعاتٍ كثيرة يدخلون في دين الله. الخطأ الشائع ظنّها قليلًا أو شخصًا واحدًا.', 3)
