INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb570dab-15f7-5e3a-9662-bbea593c466f', '6087495c-7a7e-541e-a66e-a18b184cb8ee', 'قال صديقك إنّ «إنّا أعطيناك الكوثر» من سورة النصر. ما الصواب؟', '[{"id":"a","text":"صحيح، هي من سورة النصر"},{"id":"b","text":"هي من سورة الفاتحة"},{"id":"c","text":"خطأ، هي أوّل آية من سورة الكوثر"},{"id":"d","text":"ليست في القرآن"}]'::jsonb, 'c', 'هذا خطأ؛ «إنّا أعطيناك الكوثر» أوّل آية من سورة الكوثر. أمّا سورة النصر فتبدأ بـ: إذا جاء نصر الله والفتح.', 4)
